# Worked focus: http-py-percent-encoding-query — Encode path segments and query names or values at the correct structural layer without double encoding. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_uris_origins_dns_4(target: str, host: str, allowed_hosts: set[str]) -> dict[str, object]:
    assert isinstance(target, str) and isinstance(host, str)
    https = target.startswith("https://")
    accepted = https and host.casefold() in {item.casefold() for item in allowed_hosts}
    return {"accepted": accepted, "host": host.casefold()}

